[dbo].[Kitaplar] ([Id])\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/Table[@Name='OduncIslemleri' and @Schema='dbo']/ForeignKey[@Name='FK__OduncIsle__Kitap__22951AFD']","object_type":"ForeignKey"}},{"cell_type":"markdown","source":["# [FK__OduncIsle__UyeId__21A0F6C4]"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/Table[@Name='OduncIslemleri' and @Schema='dbo']/ForeignKey[@Name='FK__OduncIsle__UyeId__21A0F6C4']","object_type":"ForeignKey"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["ALTER TABLE [dbo].[OduncIslemleri]  WITH CHECK ADD FOREIGN KEY([UyeId])\r\nREFERENCES [dbo].[Uyeler] ([Id])\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/Table[@Name='OduncIslemleri' and @Schema='dbo']/ForeignKey[@Name='FK__OduncIsle__UyeId__21A0F6C4']","object_type":"ForeignKey"}},{"cell_type":"markdown","source":["# [FK__Rezervasy__Kitap__2C1E8537]"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/Table[@Name='Rezervasyonlar' and @Schema='dbo']/ForeignKey[@Name='FK__Rezervasy__Kitap__2C1E8537']","object_type":"ForeignKey"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["ALTER TABLE [dbo].[Rezervasyonlar]  WITH CHECK ADD FOREIGN KEY([KitapId])\r\nREFERENCES [dbo].[Kitaplar] ([Id])\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/Table[@Name='Rezervasyonlar' and @Schema='dbo']/ForeignKey[@Name='FK__Rezervasy__Kitap__2C1E8537']","object_type":"ForeignKey"}},{"cell_type":"markdown","source":["# [FK__Rezervasy__UyeId__2B2A60FE]"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/Table[@Name='Rezervasyonlar' and @Schema='dbo']/ForeignKey[@Name='FK__Rezervasy__UyeId__2B2A60FE']","object_type":"ForeignKey"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["ALTER TABLE [dbo].[Rezervasyonlar]  WITH CHECK ADD FOREIGN KEY([UyeId])\r\nREFERENCES [dbo].[Uyeler] ([Id])\r\n","GO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/Table[@Name='Rezervasyonlar' and @Schema='dbo']/ForeignKey[@Name='FK__Rezervasy__UyeId__2B2A60FE']","object_type":"ForeignKey"}},{"cell_type":"markdown","source":["# [dbo].[sp_Ceza_Listele_Odenmemis]"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Ceza_Listele_Odenmemis' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_Ceza_Listele_Odenmemis]    Script Date: 27.11.2025 00:37:32 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","\r\n-- 12. Ödenmemiş Ceza Listesi\r\nCREATE PROCEDURE [dbo].[sp_Ceza_Listele_Odenmemis]\r\nAS BEGIN\r\n    SET NOCOUNT ON;\r\n    SELECT C.*, U.Ad AS UyeAdi, U.Soyad AS UyeSoyadi\r\n    FROM Cezalar AS C\r\n    INNER JOIN Uyeler AS U ON C.UyeId = U.Id\r\n    WHERE C.Odendi = 0\r\n    ORDER BY C.CezaBaslangicTarihi DESC;\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Ceza_Listele_Odenmemis' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_Ceza_Yonet]"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Ceza_Yonet' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_Ceza_Yonet]    Script Date: 27.11.2025 00:37:32 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[sp_Ceza_Yonet] (@Islem NVARCHAR(20), @Id INT = NULL) AS\r\nBEGIN\r\n    IF @Islem = 'select' SELECT c.*, (u.Ad + ' ' + u.Soyad) AS UyeTamAdi, k.Ad AS KitapAdi FROM Cezalar c LEFT JOIN Uyeler u ON c.UyeId = u.Id LEFT JOIN OduncIslemleri o ON c.OduncIslemiId = o.Id LEFT JOIN Kitaplar k ON o.KitapId = k.Id\r\n    IF @Islem = 'ode' UPDATE Cezalar SET Odendi = 1 WHERE Id = @Id\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Ceza_Yonet' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_Iade_Al]"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Iade_Al' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_Iade_Al]    Script Date: 27.11.2025 00:37:32 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[sp_Iade_Al] (@OduncId INT) AS\r\nBEGIN\r\n    DECLARE @KitapId INT; SELECT @KitapId = KitapId FROM OduncIslemleri WHERE Id = @OduncId\r\n    UPDATE OduncIslemleri SET TeslimTarihi = GETDATE(), Durum = 'Tamamlandı' WHERE Id = @OduncId\r\n    UPDATE Kitaplar SET Durum = 'Mevcut' WHERE Id = @KitapId\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Iade_Al' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_Kategori_Listele]"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Kategori_Listele' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_Kategori_Listele]    Script Date: 27.11.2025 00:37:32 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","\r\n-- 8. Kategori Listele\r\nCREATE PROCEDURE [dbo].[sp_Kategori_Listele]\r\nAS BEGIN SET NOCOUNT ON; SELECT * FROM Kategoriler ORDER BY Ad; END\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Kategori_Listele' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_Kategori_Yonet]"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Kategori_Yonet' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_Kategori_Yonet]    Script Date: 27.11.2025 00:37:32 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","\r\n-- =======================================================\r\n-- 6. PROSEDÜRLER (CREATE PROCEDURE)\r\n-- Raporundaki \"Create Procedure\" kutusu için\r\n-- =======================================================\r\nCREATE PROCEDURE [dbo].[sp_Kategori_Yonet] (@Islem NVARCHAR(20), @Id INT = NULL, @Ad NVARCHAR(100) = NULL) AS\r\nBEGIN\r\n    IF @Islem = 'select' SELECT * FROM Kategoriler WHERE Durum != 'Silindi'\r\n    IF @Islem = 'insert' INSERT INTO Kategoriler (Ad, Durum) VALUES (@Ad, 'Mevcut')\r\n    IF @Islem = 'update' UPDATE Kategoriler SET Ad = @Ad WHERE Id = @Id\r\n    IF @Islem = 'delete' UPDATE Kategoriler SET Durum = 'Silindi' WHERE Id = @Id\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Kategori_Yonet' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_Kitap_Listele_Musait]"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Kitap_Listele_Musait' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_Kitap_Listele_Musait]    Script Date: 27.11.2025 00:37:32 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[sp_Kitap_Listele_Musait] AS\r\nBEGIN\r\n    SELECT * FROM Kitaplar WHERE Durum = 'Mevcut' AND Id NOT IN (SELECT KitapId FROM OduncIslemleri WHERE TeslimTarihi IS NULL)\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Kitap_Listele_Musait' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_Kitap_Yonet]"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Kitap_Yonet' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_Kitap_Yonet]    Script Date: 27.11.2025 00:37:32 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","\r\nCREATE PROCEDURE [dbo].[sp_Kitap_Yonet] (@Islem NVARCHAR(20), @Id INT = NULL, @ISBN NVARCHAR(50) = NULL, @Ad NVARCHAR(100) = NULL, @YazarId INT = NULL, @KategoriId INT = NULL, @YayinEvi NVARCHAR(100) = NULL, @YayinYili INT = NULL, @Durum NVARCHAR(20) = NULL) AS\r\nBEGIN\r\n    IF @Islem = 'select' SELECT k.Id, k.ISBN, k.Ad, k.YazarId, y.Ad + ' ' + y.Soyad AS YazarTamAd, k.KategoriId, c.Ad AS KategoriAdi, k.YayinEvi, k.YayinYili, dbo.fn_BasimTuruBul(k.YayinYili) AS BasimTuru, k.Durum FROM Kitaplar k LEFT JOIN Yazarlar y ON k.YazarId = y.Id LEFT JOIN Kategoriler c ON k.KategoriId = c.Id WHERE k.Durum != 'Silindi'\r\n    IF @Islem = 'add' OR @Islem = 'insert' INSERT INTO Kitaplar (ISBN, Ad, YazarId, KategoriId, YayinEvi, YayinYili, Durum) VALUES (@ISBN, @Ad, @YazarId, @KategoriId, @YayinEvi, @YayinYili, 'Mevcut')\r\n    IF @Islem = 'update' UPDATE Kitaplar SET ISBN=@ISBN, Ad=@Ad, YazarId=@YazarId, KategoriId=@KategoriId, YayinEvi=@YayinEvi, YayinYili=@YayinYili WHERE Id=@Id\r\n    IF @Islem = 'delete' UPDATE Kitaplar SET Durum='Silindi' WHERE Id=@Id\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Kitap_Yonet' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_Odunc_Listele_Aktif]"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Odunc_Listele_Aktif' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_Odunc_Listele_Aktif]    Script Date: 27.11.2025 00:37:32 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","\r\nCREATE PROCEDURE [dbo].[sp_Odunc_Listele_Aktif] AS\r\nBEGIN\r\n    SELECT o.Id, o.UyeId, o.KitapId, o.VerilisTarihi AS OduncAlmaTarihi, o.BeklenenIadeTarihi AS PlanlananIadeTarihi, o.TeslimTarihi, o.Durum, k.Ad AS KitapAdi, k.ISBN AS KitapISBN, (u.Ad + ' ' + u.Soyad) AS UyeTamAdi FROM OduncIslemleri o JOIN Kitaplar k ON o.KitapId = k.Id JOIN Uyeler u ON o.UyeId = u.Id WHERE o.TeslimTarihi IS NULL\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Odunc_Listele_Aktif' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_Odunc_Ver]"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Odunc_Ver' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_Odunc_Ver]    Script Date: 27.11.2025 00:37:32 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[sp_Odunc_Ver] (@UyeId INT, @KitapId INT, @IadeTarihi DATETIME) AS\r\nBEGIN\r\n    INSERT INTO OduncIslemleri (UyeId, KitapId, VerilisTarihi, BeklenenIadeTarihi, Durum) VALUES (@UyeId, @KitapId, GETDATE(), @IadeTarihi, 'Devam Ediyor')\r\n    UPDATE Kitaplar SET Durum = 'Odunc Verildi' WHERE Id = @KitapId\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Odunc_Ver' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_Rezervasyon_Iptal]"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Rezervasyon_Iptal' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_Rezervasyon_Iptal]    Script Date: 27.11.2025 00:37:32 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[sp_Rezervasyon_Iptal] (@RezervasyonId INT) AS\r\nBEGIN\r\n    UPDATE Rezervasyonlar SET Durum = 'İptal' WHERE Id = @RezervasyonId\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Rezervasyon_Iptal' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_Rezervasyon_Listele_Aktif]"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Rezervasyon_Listele_Aktif' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_Rezervasyon_Listele_Aktif]    Script Date: 27.11.2025 00:37:32 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[sp_Rezervasyon_Listele_Aktif] AS\r\nBEGIN\r\n    SELECT r.Id, r.UyeId, r.KitapId, r.RezervasyonTarihi, r.Durum, k.Ad AS KitapAdi, k.ISBN AS KitapISBN, (u.Ad + ' ' + u.Soyad) AS UyeTamAdi FROM Rezervasyonlar r JOIN Kitaplar k ON r.KitapId = k.Id JOIN Uyeler u ON r.UyeId = u.Id WHERE r.Durum = 'Aktif' OR r.Durum = 'Sıra Geldi'\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Rezervasyon_Listele_Aktif' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_Rezervasyon_Yap]"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Rezervasyon_Yap' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_Rezervasyon_Yap]    Script Date: 27.11.2025 00:37:32 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[sp_Rezervasyon_Yap] (@UyeId INT, @KitapId INT) AS\r\nBEGIN\r\n    INSERT INTO Rezervasyonlar (UyeId, KitapId, RezervasyonTarihi, Durum) VALUES (@UyeId, @KitapId, GETDATE(), 'Aktif')\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Rezervasyon_Yap' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_Uye_Yonet]"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Uye_Yonet' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_Uye_Yonet]    Script Date: 27.11.2025 00:37:32 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[sp_Uye_Yonet]\r\n(\r\n    @Islem NVARCHAR(20),\r\n    @Id INT = NULL,\r\n    @Ad NVARCHAR(50) = NULL,\r\n    @Soyad NVARCHAR(50) = NULL,\r\n    @Telefon NVARCHAR(20) = NULL,\r\n    @Eposta NVARCHAR(100) = NULL,\r\n    @CezaPuani INT = 0\r\n)\r\nAS\r\nBEGIN\r\n    -- 1. LİSTELEME\r\n    IF @Islem = 'select' \r\n    BEGIN\r\n        SELECT \r\n            Id,\r\n            Ad,\r\n            Soyad,\r\n            Telefon,\r\n            Eposta,\r\n            -- KRİTİK NOKTA BURASI:\r\n            Eposta AS Email, -- C# kodun 'Email' arıyor, veritabanı 'Eposta' veriyor. Bu satır onları eşitler.\r\n            CezaPuani,\r\n            Durum,\r\n            (Ad + ' ' + Soyad) AS TamAd \r\n        FROM Uyeler \r\n        WHERE Durum != 'Silindi'\r\n    END\r\n\r\n    -- 2. EKLEME (Hem 'insert' hem 'add' kabul etsin ki C# tarafı ne gönderirse göndersin çalışsın)\r\n    ELSE IF @Islem = 'insert' OR @Islem = 'add'\r\n    BEGIN\r\n        INSERT INTO Uyeler (Ad, Soyad, Telefon, Eposta, CezaPuani, Durum) \r\n        VALUES (@Ad, @Soyad, @Telefon, @Eposta, 0, 'Mevcut')\r\n    END\r\n\r\n    -- 3. GÜNCELLEME\r\n    ELSE IF @Islem = 'update' \r\n    BEGIN\r\n        UPDATE Uyeler \r\n        SET Ad=@Ad, Soyad=@Soyad, Telefon=@Telefon, Eposta=@Eposta \r\n        WHERE Id=@Id\r\n    END\r\n\r\n    -- 4. SİLME\r\n    ELSE IF @Islem = 'delete' \r\n    BEGIN\r\n        UPDATE Uyeler SET Durum='Silindi' WHERE Id=@Id\r\n    END\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Uye_Yonet' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_Yazar_Listele]"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Yazar_Listele' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_Yazar_Listele]    Script Date: 27.11.2025 00:37:32 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","\r\n-- 9. Yazar Listele\r\nCREATE PROCEDURE [dbo].[sp_Yazar_Listele]\r\nAS BEGIN SET NOCOUNT ON; SELECT * FROM Yazarlar ORDER BY Ad; END\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Yazar_Listele' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_Yazar_Yonet]"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Yazar_Yonet' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_Yazar_Yonet]    Script Date: 27.11.2025 00:37:32 ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","\r\nCREATE PROCEDURE [dbo].[sp_Yazar_Yonet] (@Islem NVARCHAR(20), @Id INT = NULL, @Ad NVARCHAR(50) = NULL, @Soyad NVARCHAR(50) = NULL) AS\r\nBEGIN\r\n    IF @Islem = 'select' SELECT Id, Ad, Soyad, (Ad + ' ' + Soyad) AS TamAd, Durum FROM Yazarlar WHERE Durum != 'Silindi'\r\n    IF @Islem = 'insert' INSERT INTO Yazarlar (Ad, Soyad, Durum) VALUES (@Ad, @Soyad, 'Mevcut')\r\n    IF @Islem = 'update' UPDATE Yazarlar SET Ad = @Ad, Soyad = @Soyad WHERE Id = @Id\r\n    IF @Islem = 'delete' UPDATE Yazarlar SET Durum = 'Silindi' WHERE Id = @Id\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='mssql_okul']/Database[@Name='KutuphaneOtomasyonu_242516042']/StoredProcedure[@Name='sp_Yazar_Yonet' and @Schema='dbo']","object_type":"StoredProcedure"}}]}